105	describe("bundled plugin naming guardrails", () => {
106	  it.each([
107	    {
108	      name: "keeps bundled workspace package names anchored to the plugin id",
109	      message: `Bundled extension package names must stay anchored to the manifest id via @openclaw/<id> or an approved suffix (${ALLOWED_PACKAGE_SUFFIXES.join(", ")}). Update the plugin naming docs and this invariant before adding a new naming form.`,
110	      collectMismatches: (records: BundledPluginRecord[]) =>
111	        records
112	          .filter(
113	            ({ packageName, manifestId }) =>
114	              !resolveAllowedPackageNamesForId(manifestId).includes(packageName),
115	          )
116	          .map(
117	            ({ dirName, packageName, manifestId }) =>
118	              `${dirName}: ${packageName} (id=${manifestId})`,
119	          ),
120	    },
121	    {
122	      name: "keeps bundled workspace directories aligned with the plugin id unless explicitly allowlisted",
123	      message:
124	        "Bundled extension directory names should match openclaw.plugin.json:id. If a legacy exception is unavoidable, add it to DIR_ID_EXCEPTIONS with a comment.",
125	      collectMismatches: (records: BundledPluginRecord[]) =>
126	        records
127	          .filter(
128	            ({ dirName, manifestId }) => (DIR_ID_EXCEPTIONS.get(dirName) ?? dirName) !== manifestId,
129	          )
130	          .map(({ dirName, manifestId }) => `${dirName} -> ${manifestId}`),
131	    },
132	    {
133	      name: "keeps bundled openclaw.install.npmSpec aligned with the package name",
134	      message:
135	        "Bundled openclaw.install.npmSpec values must match the package name so install/update paths stay deterministic.",
136	      collectMismatches: (records: BundledPluginRecord[]) =>
137	        records
138	          .filter(
139	            ({ installNpmSpec, packageName }) =>
140	              typeof installNpmSpec === "string" && installNpmSpec !== packageName,
141	          )
142	          .map(
143	            ({ dirName, packageName, installNpmSpec }) =>
144	              `${dirName}: package=${packageName}, npmSpec=${installNpmSpec}`,
145	          ),
146	    },
147	    {
148	      name: "keeps bundled channel ids aligned with the canonical plugin id",
149	      message:
150	        "Bundled openclaw.channel.id values must match openclaw.plugin.json:id for the owning plugin.",
151	      collectMismatches: (records: BundledPluginRecord[]) =>
152	        records
153	          .filter(
154	            ({ channelId, manifestId }) =>
155	              typeof channelId === "string" && channelId !== manifestId,
156	          )
157	          .map(
158	            ({ dirName, manifestId, channelId }) =>
159	              `${dirName}: channel=${channelId}, id=${manifestId}`,
160	          ),
161	    },
162	  ] as const)("$name", ({ message, collectMismatches }) => {
163	    expectNoBundledPluginNamingMismatches({
164	      message,
165	      collectMismatches,
166	    });
167	  });
168	});
