/**
 * Minimal PulseBoard API client.
 * All methods are stubs — PulseBoard is a fictional platform.
 */
export class PulseBoardClient {
  readonly apiToken: string;
  readonly serverUrl: string;

  constructor(opts: PulseBoardClientOptions) {
    this.apiToken = opts.apiToken;
    this.serverUrl = opts.serverUrl.replace(/\/$/, "");
  }

  /** Send a direct message to a user. */
  async sendDirectMessage(username: string, text: string): Promise<PulseBoardMessage> {
    // TODO: POST /v1/dm  { to: username, text }
    return {
      messageId: `pb-dm-${Date.now()}`,
      to: username,
      text,
      timestamp: Date.now(),
    };
  }

  /** Post a message to a board (group). */
  async postToBoard(boardName: string, text: string): Promise<PulseBoardMessage> {
    // TODO: POST /v1/boards/{boardName}/messages  { text }
    const name = boardName.startsWith("#") ? boardName.slice(1) : boardName;
    return {
      messageId: `pb-board-${Date.now()}`,
      to: `#${name}`,
      text,
      timestamp: Date.now(),
    };
  }

  /** Verify the API token is valid. Returns the authenticated username. */
  async verifyToken(): Promise<string> {
    // TODO: GET /v1/me  → { username }
    return "pulseboard-user";
  }
}
