```typescript
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { PulseBoardClient } from "./client.js";
import { isBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { resolvePulseBoardAccount } from "./types.js";

export async function sendPulseBoardMessage(
  to: string,
  text: string,
  opts: {
    cfg: { channels?: unknown };
    accountId?: string | null;
  },
) {
  const account = resolvePulseBoardAccount({ cfg: opts.cfg, accountId: opts.accountId });
  if (!account.configured) {
    throw new Error("PulseBoard: apiToken is not configured");
  }

  const client = new PulseBoardClient({
    apiToken: account.apiToken,
    serverUrl: account.serverUrl,
  });

  let result;
  if (isBoardTarget(to)) {
    result = await client.postToBoard(to, text);
  } else {
    result = await client.sendDirectMessage(to, text);
  }

  return attachChannelToResult("pulseboard", {
    to: result.to,
    messageId: result.messageId,
  });
}
```

