### 10. `extensions/pulseboard/src/normalize.ts`

Normalizes user-facing target strings into canonical forms and back.

```typescript
/**
 * Normalize a raw PulseBoard target.
 * - "@alice" or "alice"  → "alice"  (direct message target)
 * - "#news" or "news"    → "#news"  (board target; kept with # prefix)
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;
  if (trimmed.startsWith("#")) {
    // Board: keep the # prefix and lowercase the name.
    const board = trimmed.slice(1).toLowerCase();
    return board ? `#${board}` : undefined;
  }
  // Direct: strip @ prefix if present and lowercase.
  const user = trimmed.startsWith("@") ? trimmed.slice(1) : trimmed;
  return user.toLowerCase() || undefined;
}

/** Returns true if this target looks like a board (group) rather than a user. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/** Returns true if the raw input looks like a PulseBoard identifier. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  return (
    trimmed.startsWith("@") ||
    trimmed.startsWith("#") ||
    /^[a-z0-9_-]{2,64}$/i.test(trimmed)
  );
}
```

