          buildPassiveChannelStatusSummary(snapshot, {
            serverUrl: snapshot.serverUrl ?? null,
          }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: { serverUrl: account.serverUrl },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account as ResolvedPulseBoardAccount;
        if (!account.configured) {
          throw new Error("PulseBoard: apiToken is not configured");
        }

        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`,
        );

        const { PulseBoardClient } = await import("./client.js");
        const client = new PulseBoardClient({
          apiToken: account.apiToken,
          serverUrl: account.serverUrl,
        });

        activeClients.set(account.accountId, client);

        ctx.setStatus({ accountId: account.accountId });
        ctx.log?.info(`[${account.accountId}] PulseBoard provider started`);

        return {
          stop: () => {
            activeClients.delete(account.accountId);
            ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
          },
        };
      },
    },
  },

  pairing: {
    text: {
      idLabel: "pulseBoardUsername",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => entry.trim().toLowerCase().replace(/^@/, ""),
      notify: async ({ id, message }) => {
        const client = activeClients.get(DEFAULT_ACCOUNT_ID);
        if (client) {
          await client.sendDirectMessage(id, message);
        }
      },
    },
  },

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      return sendPulseBoardMessage(to, text ?? "", { cfg, accountId });
    },
    sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) => {
      const body = [text, mediaUrl ? `Attachment: ${mediaUrl}` : ""]
        .filter(Boolean)
        .join("\n\n");
      return sendPulseBoardMessage(to, body, { cfg, accountId });
    },
  },
});
