import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";

export interface PulseBoardAccountConfig {
  enabled?: boolean;
  name?: string;
  apiToken?: SecretInput;
  serverUrl?: string;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
}

export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  apiToken: string;
  serverUrl: string;
  config: PulseBoardAccountConfig;
}

const DEFAULT_SERVER_URL = "https://api.pulseboard.example";

export function resolvePulseBoardAccount(opts: {
  cfg: { channels?: unknown };
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = opts.accountId ?? DEFAULT_ACCOUNT_ID;
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)
    ?.pulseboard as PulseBoardAccountConfig | undefined;

  const apiToken = normalizeSecretInputString(pbCfg?.apiToken) ?? "";
  const configured = Boolean(apiToken);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured,
    apiToken,
    serverUrl: pbCfg?.serverUrl?.trim() || DEFAULT_SERVER_URL,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      apiToken: pbCfg?.apiToken,
      serverUrl: pbCfg?.serverUrl,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
    },
  };
}
```

