### 15. `extensions/pulseboard/src/channel.ts` ← Core implementation

This is the main `ChannelPlugin` implementation. Modeled on the Nostr plugin (single-account, top-level config) but with `chatTypes: ["direct", "group"]` and board routing, mirroring the IRC group handling pattern.

```typescript
import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { buildPassiveChannelStatusSummary } from "openclaw/plugin-sdk/extension-shared";
import { createComputedAccountStatusAdapter } from "openclaw/plugin-sdk/status-helpers";
import { DEFAULT_ACCOUNT_ID, type ChannelPlugin } from "../runtime-api.js";
import { pulseBoardChannelConfigSchema } from "./config-schema.js";
import { isBoardTarget, looksLikePulseBoardTargetId, normalizePulseBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendPulseBoardMessage } from "./send.js";
import { pulseBoardSetupAdapter } from "./setup-core.js";
import { pulseBoardSetupWizard } from "./setup-surface.js";
import { resolvePulseBoardAccount, type ResolvedPulseBoardAccount } from "./types.js";

// Active client handles keyed by accountId (used for inbound polling and pairing replies).
const activeClients = new Map<string, import("./client.js").PulseBoardClient>();

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint:
    "Run: openclaw config set channels.pulseboard.allowFrom <username>  or use pairing.",
  normalizeEntry: (raw) => raw.trim().toLowerCase().replace(/^@/, ""),
});

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: (cfg) => {
    const account = resolvePulseBoardAccount({ cfg });
    return account.configured ? [account.accountId] : [];
  },
  defaultAccountId: (cfg) => resolvePulseBoardAccount({ cfg }).accountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "apiToken", "serverUrl", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((e) => String(e).trim().toLowerCase().replace(/^@/, ""))
      .filter(Boolean),
});

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board platform with boards and direct messages",
      order: 90,
      quickstartAllowFrom: true,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: pulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: { serverUrl: account.serverUrl },
        }),
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardTargetId,
        hint: "<@username|#board-name>",
      },
      inferTargetChatType: (params) =>
        isBoardTarget(params.to) ? "group" : "direct",
    },
    groups: {
      resolveRequireMention: () => true, // boards require @mention by default
    },
    status: {
      ...createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
        defaultRuntime: { accountId: DEFAULT_ACCOUNT_ID },
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot, {
            serverUrl: snapshot.serverUrl ?? null,
          }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: { serverUrl: account.serverUrl },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account as ResolvedPulseBoardAccount;
        if (!account.configured) {
          throw new Error("PulseBoard: apiToken is not configured");
        }

        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`,
        );

        const { PulseBoardClient } = await import("./client.js");
        const client = new PulseBoardClient({
          apiToken: account.apiToken,
          serverUrl: account.serverUrl,
        });

        activeClients.set(account.accountId, client);

        ctx.setStatus({ accountId: account.accountId });
        ctx.log?.info(`[${account.accountId}] PulseBoard provider started`);

        return {
          stop: () => {
            activeClients.delete(account.accountId);
            ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
          },
        };
      },
    },
  },

  pairing: {
    text: {
      idLabel: "pulseBoardUsername",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => entry.trim().toLowerCase().replace(/^@/, ""),
      notify: async ({ id, message }) => {
        const client = activeClients.get(DEFAULT_ACCOUNT_ID);
        if (client) {
          await client.sendDirectMessage(id, message);
        }
      },
    },
  },

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      return sendPulseBoardMessage(to, text ?? "", { cfg, accountId });
    },
    sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) => {
      const body = [text, mediaUrl ? `Attachment: ${mediaUrl}` : ""]
        .filter(Boolean)
        .join("\n\n");
      return sendPulseBoardMessage(to, body, { cfg, accountId });
    },
  },
});
```

