  validateInput: createSetupInputPresenceValidator({
    whenNotUseEnv: [
      { someOf: ["host"], message: "Pulseboard requires host." },
      { someOf: ["apiKey"], message: "Pulseboard requires apiKey." },
    ],
  }),
  applyAccountConfig: ({ cfg, accountId, input }) => {
    const setupInput = input as PulseboardSetupInput;
    const namedConfig = applyAccountNameToChannelSection({
      cfg,
      channelKey: channel,
      accountId,
      name: setupInput.name,
    });
    const portInput =
      typeof setupInput.port === "number" ? String(setupInput.port) : String(setupInput.port ?? "");
    const patch: Partial<PulseboardAccountConfig> = {
      enabled: true,
      host: setupInput.host?.trim(),
      port: portInput ? parsePort(portInput, setupInput.tls === false ? 80 : 443) : undefined,
      tls: setupInput.tls,
      apiKey: setupInput.apiKey?.trim(),
      channels: setupInput.channels,
    };
    return patchScopedAccountConfig({
      cfg: namedConfig,
      channelKey: channel,
      accountId,
      patch,
    }) as CoreConfig;
  },
};
