```typescript
import type { DmPolicy } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createAllowFromSection,
  createPromptParsedAllowFromForAccount,
  createStandardChannelSetupStatus,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy } from "openclaw/plugin-sdk/setup";
import type { ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import type { WizardPrompter } from "openclaw/plugin-sdk/setup";
import { normalizePulseboardAllowEntry } from "./normalize.js";
import {
  pulseboardSetupAdapter,
  parsePort,
  setPulseboardAllowFrom,
  setPulseboardDmPolicy,
  setPulseboardGroupAccess,
  updatePulseboardAccountConfig,
} from "./setup-core.js";
import type { CoreConfig, PulseboardAccountConfig } from "./types.js";

const channel = "pulseboard" as const;
const USE_ENV_FLAG = "__pulseboardUseEnv";
const TLS_FLAG = "__pulseboardTls";

function parseListInput(raw: string): string[] {
  return raw
    .split(/[\n,;]+/g)
    .map((entry) => entry.trim())
    .filter(Boolean);
}

function normalizeGroupEntry(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  return `#${trimmed.replace(/^#+/, "")}`;
}

const promptPulseboardAllowFrom = createPromptParsedAllowFromForAccount<CoreConfig>({
  defaultAccountId: () => DEFAULT_ACCOUNT_ID,
  noteTitle: "Pulseboard allowlist",
  noteLines: [
    "Allowlist Pulseboard DMs by sender ID.",
    "Examples:",
    "- user123",
    "- alice",
    "Multiple entries: comma-separated.",
  ],
  message: "Pulseboard allowFrom (user ID)",
  placeholder: "user123, alice",
  parseEntries: (raw) => ({
    entries: parseListInput(raw)
      .map((entry) => normalizePulseboardAllowEntry(entry))
      .filter(Boolean),
  }),
  getExistingAllowFrom: ({ cfg }) => cfg.channels?.pulseboard?.allowFrom ?? [],
  applyAllowFrom: ({ cfg, allowFrom }) => setPulseboardAllowFrom(cfg, allowFrom),
});

const pulseboardDmPolicy: ChannelSetupDmPolicy = {
  label: "Pulseboard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy) => setPulseboardDmPolicy(cfg as CoreConfig, policy),
  promptAllowFrom: async ({ cfg, prompter, accountId }) =>
    await promptPulseboardAllowFrom({
      cfg: cfg as CoreConfig,
      prompter,
      accountId,
    }),
};

export const pulseboardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "Pulseboard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs host + apiKey",
    configuredHint: "configured",
    unconfiguredHint: "needs host + apiKey",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => {
      const pulseCfg = (cfg as CoreConfig).channels?.pulseboard;
      return !!(pulseCfg?.host && pulseCfg?.apiKey);
    },
  }),
  introNote: {
    title: "Pulseboard setup",
    lines: [
      "Pulseboard needs server host + API key.",
      "Recommended: TLS on port 443.",
      'Set channels.pulseboard.groupPolicy="allowlist" and channels.pulseboard.groups for channel access control.',
      "Env vars supported: PULSEBOARD_HOST, PULSEBOARD_PORT, PULSEBOARD_TLS, PULSEBOARD_API_KEY, PULSEBOARD_CHANNELS.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg }) => {
      const pulseCfg = (cfg as CoreConfig).channels?.pulseboard;
      return !pulseCfg?.host || !pulseCfg?.apiKey;
    },
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
    const pulseCfg = (cfg as CoreConfig).channels?.pulseboard;
    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
    const envHost = isDefaultAccount ? process.env.PULSEBOARD_HOST?.trim() : "";
    const envKey = isDefaultAccount ? process.env.PULSEBOARD_API_KEY?.trim() : "";
    const envReady = Boolean(envHost && envKey && !pulseCfg?.host && !pulseCfg?.apiKey);

    if (envReady) {
      const useEnv = await prompter.confirm({
        message: "PULSEBOARD_HOST and PULSEBOARD_API_KEY detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return {
          cfg: updatePulseboardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
          credentialValues: {
            ...credentialValues,
            [USE_ENV_FLAG]: "1",
          },
        };
      }
    }

    const tls = await prompter.confirm({
      message: "Use TLS for Pulseboard?",
      initialValue: pulseCfg?.tls ?? true,
    });
    return {
      cfg: updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
        enabled: true,
        tls,
      }),
      credentialValues: {
        ...credentialValues,
        [USE_ENV_FLAG]: "0",
        [TLS_FLAG]: tls ? "1" : "0",
      },
    };
  },
  credentials: [],
  textInputs: [
    {
      inputKey: "httpHost",
      message: "Pulseboard server host",
      currentValue: ({ cfg, accountId }) =>
        (cfg as CoreConfig).channels?.pulseboard?.host || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          host: value,
        }),
    },
    {
      inputKey: "httpPort",
      message: "Pulseboard server port",
      currentValue: ({ cfg, accountId }) =>
        String((cfg as CoreConfig).channels?.pulseboard?.port ?? ""),
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      initialValue: ({ credentialValues }) => {
        const tls = credentialValues[TLS_FLAG] === "0" ? false : true;
        return String(tls ? 443 : 80);
      },
      validate: ({ value }) => {
        const parsed = Number.parseInt(String(value ?? "").trim(), 10);
        return Number.isFinite(parsed) && parsed >= 1 && parsed <= 65535
          ? undefined
          : "Use a port between 1 and 65535";
      },
      normalizeValue: ({ value }) => String(parsePort(String(value), 443)),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          port: parsePort(String(value), 443),
        }),
    },
    {
      inputKey: "token",
      message: "Pulseboard API Key",
      currentValue: ({ cfg, accountId }) =>
        (cfg as CoreConfig).channels?.pulseboard?.apiKey || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          apiKey: value,
        }),
    },
    {
      inputKey: "groupChannels",
      message: "Pulseboard channels to monitor (optional, comma-separated)",
      placeholder: "#general, #dev",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) =>
        (cfg as CoreConfig).channels?.pulseboard?.channels?.join(", "),
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      normalizeValue: ({ value }) =>
        parseListInput(String(value))
          .map((entry) => normalizeGroupEntry(entry))
          .filter((entry): entry is string => Boolean(entry && entry !== "*"))
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const channels = parseListInput(String(value))
          .map((entry) => normalizeGroupEntry(entry))
          .filter((entry): entry is string => Boolean(entry && entry !== "*"));
        return updatePulseboardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          channels,
        });
      },
    },
  ],
};
