  resolveAllowFrom: () => [],
  policyPathSuffix: "dmPolicy",
  normalizeEntry: (raw) => normalizePulseboardAllowEntry(raw),
});

export const pulseboardPlugin: ChannelPlugin<
  { accountId: string; configured: boolean },
  PulseboardProbe
> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      ...meta,
      quickstartAllowFrom: true,
