      ...pulseboardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {},
        }),
    },
    messaging: {
      normalizeTarget: normalizePulseboardMessagingTarget,
      targetResolver: {
        looksLikeId: looksLikePulseboardTargetId,
        hint: "<#channel|user>",
      },
    },
    resolver: {
      resolveTargets: async ({ inputs, kind }) => {
        return inputs.map((input) => {
          const normalized = normalizePulseboardMessagingTarget(input);
          if (!normalized) {
            return {
              input,
              resolved: false,
              note: "invalid Pulseboard target",
            };
          }
          if (kind === "group") {
            const groupId = isChannelTarget(normalized) ? normalized : `#${normalized}`;
            return {
              input,
              resolved: true,
              id: groupId,
              name: groupId,
            };
          }
          if (isChannelTarget(normalized)) {
            return {
              input,
              resolved: false,
              note: "expected user target",
            };
          }
          return {
            input,
            resolved: true,
            id: normalized,
            name: normalized,
          };
        });
      },
    },
    status: createComputedAccountStatusAdapter<
      { accountId: string; configured: boolean },
      PulseboardProbe
    >({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      buildChannelSummary: ({ account }) => ({
        id: account.accountId,
        label: "Pulseboard",
        status: "idle",
      }),
      resolveAccountSnapshot: ({ account }) => ({
        accountId: account.accountId,
        configured: account.configured,
        enabled: true,
        extra: {},
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info("[pulseboard] starting Pulseboard provider (MVP)");
        // TODO: Implement actual monitoring/listening
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseboardUser",
      message: "Pairing approved! You can now chat.",
      normalizeAllowEntry: (entry) => normalizePulseboardAllowEntry(entry),
      notify: async ({ id, message }) => {
        const target = normalizePairingTarget(id);
        if (!target) {
          throw new Error(`invalid Pulseboard pairing id: ${id}`);
        }
        await sendMessagePulseboard(target, message);
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseboardDmPolicy,
    collectWarnings: () => [],
  },
  outbound: {
    base: {
      deliveryMode: "direct",
      chunkerMode: "markdown",
      textChunkLimit: 350,
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ cfg, to, text, accountId, replyToId }) =>
        await sendMessagePulseboard(to, text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
          replyTo: replyToId ?? undefined,
        }),
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
        await sendMessagePulseboard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
          replyTo: replyToId ?? undefined,
        }),
    },
  },
});
```

---

## 3. KEY PATTERNS TO UNDERSTAND

### Pattern 1: Configuration Flow
1. **Config Schema** (`config-schema.ts`): Zod schema defines validation
2. **Account Resolution** (`types.ts`): Functions to resolve and normalize config
3. **Setup Adapter** (`setup-core.ts`): Programmatic config application
4. **Setup Wizard** (`setup-surface.ts`): Interactive UI prompts
5. **Channel Plugin** (`channel.ts`): Uses resolved config via adapters

### Pattern 2: Message Flow (Inbound)
1. Message arrives via listener (e.g., monitoring connection)
2. Normalize sender ID using `normalizeXxxAllowEntry()`
3. Check allowlist/DM policy using `resolveXxxAllowlistMatch()`
4. Dispatch via SDK helpers like `dispatchInboundDirectDmWithRuntime()`

### Pattern 3: Message Flow (Outbound)
1. `sendMessage()` called with target and text
2. Normalize target using `normalizeXxxMessagingTarget()`
3. Get runtime config via `getXxxRuntime().config.loadConfig()`
4. Apply markdown conversions
5. Send via API/client
6. Record activity: `getXxxRuntime().channel.activity.record()`

### Pattern 4: Setup Pattern
- **Prepare phase**: Early checks and env var detection
- **Text inputs**: Prompted fields with validation and normalization
- **Policy setup**: Separate DM policy/allowlist flow
- **Credentials**: Sensitive input handling

---

## 4. KEY SDK IMPORTS TO USE

```typescript
// Core plugin SDK
import { defineChannelPluginEntry, defineSetupPluginEntry, createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { createPluginRuntimeStore } from "openclaw/plugin-sdk/runtime-store";

// Account & Config
import { normalizeAccountId, DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import { createScopedChannelConfigAdapter, createScopedDmSecurityResolver } from "openclaw/plugin-sdk/channel-config-helpers";
import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";

// Config Schema & Validation
import { buildChannelConfigSchema } from "openclaw/plugin-sdk/channel-config-schema";
import { z } from "openclaw/plugin-sdk/zod";

// Setup
import { createSetupInputPresenceValidator, patchScopedAccountConfig } from "openclaw/plugin-sdk/setup";
import { createStandardChannelSetupStatus, createPromptParsedAllowFromForAccount } from "openclaw/plugin-sdk/setup";

// Status & Runtime
import { createComputedAccountStatusAdapter, createDefaultChannelRuntimeState } from "openclaw/plugin-sdk/status-helpers";

// Message handling
import { resolveMarkdownTableMode, convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { getChatChannelMeta } from "openclaw/plugin-sdk/core";
```

---

## 5. CONFIGURATION EXAMPLE

Users will configure your plugin in their `config.json`:

```json
{
  "channels": {
    "pulseboard": {
      "enabled": true,
      "host": "api.pulseboard.com",
      "port": 443,
      "tls": true,
      "apiKey": "sk_test_...",
      "channels": ["#general", "#dev"],
      "dmPolicy": "allowlist",
      "allowFrom": ["user123", "alice"],
      "groupPolicy": "allowlist",
      "groups": {
        "#general": {
          "allowFrom": ["*"]
        },
        "#dev": {
          "allowFrom": ["alice", "bob"]
        }
      }
    }
  }
}
```

---

## 6. NOTES ON PATTERNS

**Multi-account support**: The IRC plugin shows how to support multiple accounts per channel. Nostr keeps it simple with one global account. Start simple like Nostr if Pulseboard doesn't need multi-account.

**Normalization**: All user inputs (targets, allow entries) should be normalized to a canonical form for matching.

**Runtime safety**: Always check `getXxxRuntime()` with try-catch because runtime may not be initialized during setup/configuration phases.

**Activity tracking**: Use `runtime.channel.activity.record()` to track inbound/outbound message flow for diagnostics.

**Security warnings**: Implement `collectWarnings` callback to show TLS disabled, missing auth, etc.

This structure gives you everything needed to build a production-grade channel plugin!

