167	    }),
168	};
169	
170	export const ircSetupWizard: ChannelSetupWizard = {
171	  channel,
172	  status: createStandardChannelSetupStatus({
173	    channelLabel: "IRC",
174	    configuredLabel: "configured",
175	    unconfiguredLabel: "needs host + nick",
176	    configuredHint: "configured",
177	    unconfiguredHint: "needs host + nick",
178	    configuredScore: 1,
179	    unconfiguredScore: 0,
