import {
  createAccountListHelpers,
  resolveMergedAccountConfig,
} from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import type { DmPolicy, GroupPolicy, OpenClawConfig } from "../api.js";

export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  apiToken?: string;
  apiTokenFile?: string;
  serverUrl?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  boards?: Record<string, PulseBoardBoardConfig>;
  monitorBoards?: string[];
  textChunkLimit?: number;
  defaultTo?: string;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type ResolvedPulseBoardAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  apiToken: string;
  serverUrl: string;
  config: PulseBoardAccountConfig;
};

/** Probe result shape for PulseBoard connectivity checks. */
export type PulseBoardProbe = {
  ok: boolean;
  serverUrl: string;
  latencyMs?: number;
  error?: string;
};

const {
  listAccountIds: listPulseBoardAccountIds,
  resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
} = createAccountListHelpers("pulseboard", { normalizeAccountId });

export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

function mergePulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
): PulseBoardAccountConfig {
  return resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined,
    accounts: cfg.channels?.pulseboard?.accounts as
      | Record<string, Partial<PulseBoardAccountConfig>>
      | undefined,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });
}

export function resolvePulseBoardAccount(opts: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const baseEnabled = opts.cfg.channels?.pulseboard?.enabled !== false;
  const normalized = normalizeAccountId(opts.accountId);
  const merged = mergePulseBoardAccountConfig(opts.cfg, normalized);
  const accountEnabled = merged.enabled !== false;
  const enabled = baseEnabled && accountEnabled;

  // Support env vars for the default account
  const apiToken = (
    merged.apiToken?.trim() ||
    (normalized === DEFAULT_ACCOUNT_ID ? process.env.PULSEBOARD_API_TOKEN?.trim() : "") ||
    ""
  ).trim();
  const serverUrl = (
    merged.serverUrl?.trim() ||
    (normalized === DEFAULT_ACCOUNT_ID ? process.env.PULSEBOARD_SERVER_URL?.trim() : "") ||
    ""
  ).trim();

  const config: PulseBoardAccountConfig = {
    ...merged,
    apiToken,
    serverUrl,
  };

  return {
    accountId: normalized,
    name: merged.name?.trim() || undefined,
    enabled,
    configured: Boolean(apiToken && serverUrl),
    apiToken,
    serverUrl,
    config,
  };
}

export function listEnabledPulseBoardAccounts(cfg: CoreConfig): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount({ cfg, accountId }))
    .filter((account) => account.enabled);
}

