// Target and allow-entry normalization for the PulseBoard channel plugin.
// Boards use a leading "#" (e.g. "#general"); user IDs are plain strings (e.g. "alice").

const PULSEBOARD_TARGET_PATTERN = /^[^\s:]+$/u;

/** Returns true when the target refers to a board (starts with "#"). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalize a raw messaging target to a canonical PulseBoard target string.
 * Accepts plain user IDs, board names (with or without "#"), and prefixed
 * forms like "pulseboard:alice", "board:general", or "user:alice".
 * Returns undefined if the target is blank or contains whitespace/colons.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("#")) {
      target = `#${target}`;
    }
  }
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }
  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Returns true when the raw string looks like a valid PulseBoard target ID. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/**
 * Normalize a single allowlist entry to lowercase, stripping any
 * "pulseboard:" or "user:" prefix.  Returns an empty string for blank input.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

/** Normalize an array of raw allowlist entries, dropping blanks. */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
    .filter(Boolean);
}

/**
 * Check whether `senderId` matches any entry in `allowFrom`.
 * Supports the "*" wildcard and exact-match after normalization.
 */
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  senderId: string;
}): { allowed: boolean; source?: string } {
  const allowFrom = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowFrom.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const normalizedSenderId = normalizePulseBoardAllowEntry(params.senderId);
  if (normalizedSenderId && allowFrom.has(normalizedSenderId)) {
    return { allowed: true, source: normalizedSenderId };
  }
  return { allowed: false };
}

